#include <bits/stdc++.h>
using namespace std;

const int N=210,M=8e4+10,INF=0x3f3f3f3f;

int n,p,t;
int head[N],ver[M],edge[M],val[M],nxt[M],tot=1;
int S,T,d[N],now[N];

void add(int u,int v,int w){
    ver[++tot]=v,edge[tot]=0,val[tot]=w,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,edge[tot]=0,val[tot]=w,nxt[tot]=head[v],head[v]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    queue<int> q;
    q.push(S),d[S]=1,now[S]=head[S];
    while(!q.empty()){
        int x=q.front();
        q.pop();
        for(int i=head[x],y;i;i=nxt[i])
            if(!d[y=ver[i]] && edge[i]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==T)
                    return 1;
                q.push(y);
            }
    }
    return 0;
}

int Dinic(int x,int flow){
    if(x==T)
        return flow;
    int res=0;
    for(int i=head[x],y;i && res<flow;i=nxt[i]){
        now[x]=i,y=ver[i];
        if(d[y]==d[x]+1 && edge[i]){
            int tmp=Dinic(y,min(edge[i],flow-res));
            if(!tmp)
                d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

bool check(int num){
    for(int i=2;i<=tot;i++)
        edge[i]=(val[i]<=num);
    int flow,max_flow=0;
    while(bfs())
        while(flow=Dinic(S,INF))
            max_flow+=flow;
    return max_flow>=t;
}

int main(){
    scanf("%d%d%d",&n,&p,&t);
    S=1,T=n;
    for(int i=1,u,v,w;i<=p;i++){
        scanf("%d%d%d",&u,&v,&w);
        add(u,v,w);
    }
    int l=0,r=1e6;
    while(l<r){
        int mid=l+r>>1;
        if(check(mid))
            r=mid;
        else
            l=mid+1;
    }
    printf("%d",l);
    return 0;
}
